import React from 'react';
import { Link } from 'react-router-dom';

// Componente para los íconos de redes sociales
const SocialIcons = () => {
    return (
        <div className="flex justify-center gap-4"> {/* Aumentado el gap para que los iconos no estén tan pegados */}
            {/* Rutas de las imágenes: Asegúrate que están en public/media/icons/ */}
            <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" className="opacity-90 hover:opacity-100 hover:scale-110 transition-all duration-200">
                <img src="/media/icons/facebook_icon.png" alt="Facebook" className="w-6 h-6" /> {/* Iconos un poco más grandes */}
            </a>
            <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" className="opacity-90 hover:opacity-100 hover:scale-110 transition-all duration-200">
                <img src="/media/icons/instagram_icon.png" alt="Instagram" className="w-6 h-6" /> {/* Iconos un poco más grandes */}
            </a>
            <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" className="opacity-90 hover:opacity-100 hover:scale-110 transition-all duration-200">
                <img src="/media/icons/tiktok_icon.png" alt="TikTok" className="w-6 h-6" /> {/* Iconos un poco más grandes */}
            </a>
        </div>
    );
};

function Footer() {
    const currentYear = new Date().getFullYear();

    return (
        <footer className="relative bg-yellow-50 dark:bg-neutral-800 text-neutral-700 dark:text-neutral-200 py-4 mt-auto shadow-inner transition-colors duration-300 font-sans overflow-hidden">
            {/* Imagen de fondo del footer */}
            {/* Asegúrate que footer2.png está en public/media/ */}
            <div
                className="absolute inset-0 bg-cover bg-center bg-no-repeat opacity-30 dark:opacity-20 z-0" /* Opacidad reducida para no distraer */
                style={{ backgroundImage: "url('/media/footer2.png')" }} /* */
            ></div>

            <div className="relative z-10 max-w-lg mx-auto px-4 text-base font-medium tracking-wide"> {/* max-w ajustado y text-base para letras más grandes */}

                {/* Copyright */}
                <p className="text-neutral-700 dark:text-neutral-300 text-center mb-5 leading-snug text-sm"> {/* text-sm para el copyright */}
                    © {currentYear} Repositorio Bicentenario de Bolivia. Todos los derechos reservados.
                </p>

                <div className="flex flex-col sm:flex-row justify-center items-start sm:items-center gap-10 sm:gap-20 mb-5"> {/* Ajustado gap y mb */}

                    {/* Columna Izquierda: Navegación */}
                    <div className="text-center">
                        <h3 className="text-neutral-800 dark:text-neutral-100 font-semibold mb-3 text-base uppercase"> {/* text-base para el título */}
                            Navegación
                        </h3>
                        <ul className="space-y-2 text-sm"> {/* text-sm y space-y para enlaces */}
                            <li><Link to="/acerca-de" className="text-neutral-600 dark:text-neutral-300 hover:text-yellow-600 dark:hover:text-yellow-400 transition">Acerca de</Link></li>
                            <li><Link to="/mas-de-nosotros" className="text-neutral-600 dark:text-neutral-300 hover:text-yellow-600 dark:hover:text-yellow-400 transition">Más de Nosotros</Link></li>
                            <li><Link to="/contacto" className="text-neutral-600 dark:text-neutral-300 hover:text-yellow-600 dark:hover:text-yellow-400 transition">Contacto</Link></li>
                        </ul>
                    </div>

                    {/* Columna Derecha: Solo Íconos de Redes Sociales */}
                    <div className="flex flex-col items-center justify-center pt-2"> {/* pt-2 para alinear verticalmente */}
                        <SocialIcons /> {/* Componente de íconos */}
                    </div>

                </div>

                {/* Línea divisoria */}
                <div className="w-2/3 mx-auto border-t border-neutral-300 dark:border-neutral-600 my-4"></div> {/* my ajustado */}

                {/* Cita final */}
                <p className="text-center text-sm text-neutral-500 dark:text-neutral-500 tracking-wide italic mb-1"> {/* text-sm para la cita */}
                    “Conocer nuestra historia es entender nuestro presente.”
                </p>

                {/* Crédito de Alberto Navarro */}
                <p className="text-center text-xs text-neutral-500 dark:text-neutral-500 tracking-wide"> {/* text-xs para el crédito, discreto */}
                    Titulizado por Alberto Navarro
                </p>
            </div>
        </footer>
    );
}

export default Footer;
